### 4. STATE FILE MANAGEMENT PATTERN (File Locking via Atomic Write)

**File:** `/Users/alisha/Projects/wt/cli-collab/cmd/entire/cli/session/state.go` (lines 396-435)

**Atomic Write Pattern (NO explicit locking):**
```go
// Save saves the session state atomically.
func (s *StateStore) Save(ctx context.Context, state *State) error {
	// Validate session ID to prevent path traversal
	if err := validation.ValidateSessionID(state.SessionID); err != nil {
		return fmt.Errorf("invalid session ID: %w", err)
	}

	if err := os.MkdirAll(s.stateDir, 0o750); err != nil {
		return fmt.Errorf("failed to create session state directory: %w", err)
	}

	// Marshal to JSON with proper formatting
	data, err := jsonutil.MarshalIndentWithNewline(state, "", "  ")
	if err != nil {
		return fmt.Errorf("failed to marshal session state: %w", err)
	}

	root, err := os.OpenRoot(s.stateDir)
	if err != nil {
		return fmt.Errorf("failed to open session state directory: %w", err)
	}
	defer root.Close()

	fileName := state.SessionID + ".json"
	tmpFileName := fileName + ".tmp"

	// Write to temp file first
	if err := osroot.WriteFile(root, tmpFileName, data, 0o600); err != nil {
		return fmt.Errorf("failed to write session state: %w", err)
	}

	// Atomic rename: temp → final
	stateFile := s.stateFilePath(state.SessionID)
	tmpFile := stateFile + ".tmp"
	if err := os.Rename(tmpFile, stateFile); err != nil {
		return fmt.Errorf("failed to rename session state file: %w", err)
	}
	return nil
}
```

**Key Points:**
- No explicit `flock` or `sync.Mutex` — uses atomic write pattern (write to `.tmp`, then `os.Rename()`)
- Session state dir: `.git/entire-sessions/` (shared across worktrees via git common dir)
- `os.Root` used for traversal-resistant writes (Go 1.24+, prevents path escape attacks)
- Validation via `validation.ValidateSessionID()` to prevent path traversal

**Load Pattern with Stale Detection:**
```go
func (s *StateStore) Load(ctx context.Context, sessionID string) (*State, error) {
	if err := validation.ValidateSessionID(sessionID); err != nil {
		return nil, fmt.Errorf("invalid session ID: %w", err)
	}

	root, err := os.OpenRoot(s.stateDir)
	if os.IsNotExist(err) {
		return nil, nil // Not found is not an error
	}
	if err != nil {
		return nil, fmt.Errorf("failed to open session state directory: %w", err)
	}
	defer root.Close()

	fileName := sessionID + ".json"
	data, err := osroot.ReadFile(root, fileName)
	if os.IsNotExist(err) {
		return nil, nil // Not found is not an error
	}
	if err != nil {
		return nil, fmt.Errorf("failed to read session state: %w", err)
	}

	var state State
	if err := json.Unmarshal(data, &state); err != nil {
		return nil, fmt.Errorf("failed to unmarshal session state: %w", err)
	}
	state.NormalizeAfterLoad(ctx)

	if state.IsStale() {
		logCtx := logging.WithComponent(ctx, "session")
		logging.Debug(logCtx, "deleting stale session state", slog.String("session_id", sessionID))
		_ = s.Clear(ctx, sessionID)
		return nil, nil
	}

	return &state, nil
}
